mapper.select:
SELECT id, username, nickname, phone, avatar, status, COALESCE(role, 'user') AS role, mute_until AS muteUntil, last_login_time AS lastLoginTime, create_time AS createTime FROM user_account
AND (nickname LIKE CONCAT('%', #{keyword}, '%') OR username LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}
ORDER BY create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM user_account
AND (nickname LIKE CONCAT('%', #{keyword}, '%') OR username LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}

SELECT p.id, p.title, p.author_id AS authorId, COALESCE(NULLIF(u.nickname,''), NULLIF(u.username,''), '匿名') AS authorName, b.name AS boardName, p.status, (p.is_pinned = 1) AS pinned, (p.is_featured = 1) AS featured, p.view_count AS viewCount, p.comment_count AS commentCount, p.like_count AS likeCount, p.create_time AS createTime FROM community_post p LEFT JOIN user_account u ON u.id = p.author_id LEFT JOIN community_board b ON b.id = p.board_id
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
AND p.status = #{status}
ORDER BY p.create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM community_post p LEFT JOIN user_account u ON u.id = p.author_id
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
AND p.status = #{status}

SELECT c.id, c.post_id AS postId, p.title AS postTitle, c.author_id AS authorId, COALESCE(NULLIF(u.nickname,''), NULLIF(u.username,''), '匿名') AS authorName, c.content, c.status, c.create_time AS createTime FROM community_comment c LEFT JOIN community_post p ON p.id = c.post_id LEFT JOIN user_account u ON u.id = c.author_id
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.create_time DESC LIMIT #{limit} OFFSET #{offset}
